{"action":"create","path":"helo2.html","content":"<!DOCTYPE html>
<html lang="ar" dir="rtl">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no">
<title>مغامرة ناصر 3D</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { background: #000; overflow: hidden; font-family: Arial, sans-serif; }
  canvas { display: block; }
  #ui {
    position: fixed; top: 0; left: 0; width: 100%; pointer-events: none;
    z-index: 10;
  }
  #score-bar {
    display: flex; justify-content: space-between; align-items: center;
    padding: 10px 20px;
    background: linear-gradient(180deg, rgba(0,0,0,0.7) 0%, transparent 100%);
    color: #fff; font-size: 18px; font-weight: bold;
  }
  #score-bar span { text-shadow: 0 0 10px #00ffff; }
  #health-bar-container {
    width: 150px; height: 14px;
    background: rgba(255,255,255,0.2);
    border-radius: 7px; overflow: hidden;
    border: 1px solid #fff;
  }
  #health-bar {
    height: 100%; width: 100%;
    background: linear-gradient(90deg, #ff4444, #ff0000);
    transition: width 0.3s;
    border-radius: 7px;
  }
  /* Mobile Controls */
  #mobile-controls {
    position: fixed; bottom: 0; left: 0; width: 100%;
    height: 220px; z-index: 20;
    pointer-events: none;
  }
  #joystick-area {
    position: absolute; bottom: 20px; left: 20px;
    width: 130px; height: 130px;
    pointer-events: all;
  }
  #joystick-base {
    width: 130px; height: 130px;
    background: rgba(255,255,255,0.15);
    border: 3px solid rgba(255,255,255,0.4);
    border-radius: 50%;
    position: relative;
  }
  #joystick-thumb {
    width: 55px; height: 55px;
    background: radial-gradient(circle, #00ffff, #0088ff);
    border-radius: 50%;
    position: absolute;
    top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    box-shadow: 0 0 15px #00ffff;
    transition: box-shadow 0.1s;
  }
  #action-buttons {
    position: absolute; bottom: 20px; right: 20px;
    display: grid; grid-template-columns: 60px 60px;
    grid-template-rows: 60px 60px;
    gap: 10px;
    pointer-events: all;
  }
  .action-btn {
    width: 60px; height: 60px;
    border-radius: 50%;
    border: 3px solid rgba(255,255,255,0.5);
    font-size: 22px;
    font-weight: bold;
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    user-select: none;
    -webkit-user-select: none;
    transition: transform 0.1s, box-shadow 0.1s;
    pointer-events: all;
  }
  .action-btn:active { transform: scale(0.88); }
  #btn-jump {
    background: radial-gradient(circle, #ffdd00, #ff8800);
    box-shadow: 0 0 15px #ffaa00;
    grid-column: 2; grid-row: 1;
  }
  #btn-attack {
    background: radial-gradient(circle, #ff4444, #cc0000);
    box-shadow: 0 0 15px #ff0000;
    grid-column: 1; grid-row: 2;
  }
  #btn-dash {
    background: radial-gradient(circle, #44ff88, #00aa44);
    box-shadow: 0 0 15px #00ff66;
    grid-column: 2; grid-row: 2;
  }
  #btn-camera {
    position: absolute; bottom: 160px; right: 20px;
    width: 55px; height: 55px;
    border-radius: 50%;
    background: radial-gradient(circle, #aa44ff, #6600cc);
    border: 3px solid rgba(255,255,255,0.5);
    box-shadow: 0 0 15px #aa00ff;
    font-size: 20px;
    display: flex; align-items: center; justify-content: center;
    cursor: pointer;
    pointer-events: all;
    user-select: none;
  }
  /* Overlay screens */
  .overlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0,0,0,0.85);
    display: flex; flex-direction: column;
    align-items: center; justify-content: center;
    z-index: 100; color: #fff;
  }
  .overlay h1 {
    font-size: 42px;
    background: linear-gradient(90deg, #00ffff, #ff00ff, #ffff00);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    margin-bottom: 10px;
    text-align: center;
  }
  .overlay p { font-size: 18px; color: #aaa; margin-bottom: 30px; text-align: center; }
  .overlay button {
    padding: 16px 50px;
    font-size: 22px;
    border: none;
    border-radius: 40px;
    background: linear-gradient(90deg, #00ffff, #0055ff);
    color: #fff;
    cursor: pointer;
    font-weight: bold;
    box-shadow: 0 0 25px #00aaff;
    margin: 8px;
    transition: transform 0.15s;
  }
  .overlay button:active { transform: scale(0.93); }
  #game-over-screen { display: none; }
  #win-screen { display: none; }
  #nasser-label {
    position: fixed; top: 50%; left: 50%;
    transform: translate(-50%, -50%);
    font-size: 28px; font-weight: bold;
    color: #00ffff;
    text-shadow: 0 0 20px #00ffff;
    pointer-events: none;
    z-index: 5;
    opacity: 0;
    transition: opacity 0.5s;
  }
</style>
</head>
<body>

<canvas id="gameCanvas"></canvas>

<!-- UI -->
<div id="ui">
  <div id="score-bar">
    <span>⭐ النقاط: <span id="score">0</span></span>
    <span>🦸 ناصر</span>
    <div>
      <div style="font-size:12px;color:#aaa;margin-bottom:3px;">❤️ الصحة</div>
      <div id="health-bar-container"><div id="health-bar"></div></div>
    </div>
  </div>
</div>

<!-- Nasser label -->
<div id="nasser-label">🦸 ناصر</div>

<!-- Mobile Controls -->
<div id="mobile-controls">
  <div id="joystick-area">
    <div id="joystick-base">
      <div id="joystick-thumb"></div>
    </div>
  </div>
  <div id="btn-camera">📷</div>
  <div id="action-buttons">
    <button class="action-btn" id="btn-jump">⬆</button>
    <button class="action-btn" id="btn-attack">⚔</button>
    <button class="action-btn" id="btn-dash">💨</button>
  </div>
</div>

<!-- Start Screen -->
<div class="overlay" id="start-screen">
  <h1>🦸 مغامرة ناصر 3D</h1>
  <p>ساعد ناصر في جمع النجوم وهزيمة الأعداء!</p>
  <p style="font-size:14px;color:#666;">استخدم الجويستيك للتحرك • ⬆ قفز • ⚔ هجوم • 💨 اندفاع</p>
  <button onclick="startGame()">🎮 ابدأ اللعبة</button>
</div>

<!-- Game Over -->
<div class="overlay" id="game-over-screen">
  <h1>💀 انتهت اللعبة</h1>
  <p id="final-score-go"></p>
  <button onclick="restartGame()">🔄 العب مجدداً</button>
</div>

<!-- Win -->
<div class="overlay" id="win-screen">
  <h1>🏆 فزت يا ناصر!</h1>
  <p id="final-score-win"></p>
  <button onclick="restartGame()">🔄 العب مجدداً</button>
</div>

<script>
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

function resize() {
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
}
resize();
window.addEventListener('resize', resize);

// ===== GAME STATE =====
let gameRunning = false;
let score = 0;
let health = 100;
let cameraAngle = 0;
let cameraY = 0.4;
let gameTime = 0;
let particles = [];
let floatingTexts = [];

// ===== PLAYER =====
let player = {
  x: 0, y: 0, z: 0,
  vx: 0, vy: 0, vz: 0,
  onGround: false,
  attacking: false,
  attackTimer: 0,
  dashing: false,
  dashTimer: 0,
  dashCooldown: 0,
  rotation: 0,
  animFrame: 0,
  animTimer: 0,
  invincible: 0,
};

// ===== WORLD =====
let platforms = [];
let stars = [];
let enemies = [];
let coins = [];

function generateWorld() {
  platforms = [];
  stars = [];
  enemies = [];
  coins = [];

  // Ground
  platforms.push({ x: 0, y: -1, z: 0, w: 20, h: 0.5, d: 20, color: '#2d5a27' });

  // Platforms
  let configs = [
    { x: 5, y: 1, z: 0, w: 4, h: 0.4, d: 4, color: '#8B4513' },
    { x: -5, y: 2, z: 3, w: 3, h: 0.4, d: 3, color: '#8B4513' },
    { x: 0, y: 3, z: -5, w: 4, h: 0.4, d: 4, color: '#8B4513' },
    { x: 7, y: 4, z: -4, w: 3, h: 0.4, d: 3, color: '#cd853f' },
    { x: -7, y: 5, z: -2, w: 3, h: 0.4, d: 3, color: '#cd853f' },
    { x: 3, y: 6, z: 5, w: 3, h: 0.4, d: 3, color: '#daa520' },
    { x: -3, y: 7, z: -7, w: 4, h: 0.4, d: 4, color: '#daa520' },
    { x: 0, y: 9, z: 0, w: 5, h: 0.4, d: 5, color: '#ffd700' },
  ];
  platforms.push(...configs);

  // Stars
  for (let i = 0; i < 15; i++) {
    stars.push({
      x: (Math.random() - 0.5) * 16,
      y: Math.random() * 10,
      z: (Math.random() - 0.5) * 16,
      collected: false,
      bob: Math.random() * Math.PI * 2,
    });
  }

  // Coins
  for (let i = 0; i < 20; i++) {
    coins.push({
      x: (Math.random() - 0.5) * 18,
      y: Math.random() * 8,
      z: (Math.random() - 0.5) * 18,
      collected: false,
      bob: Math.random() * Math.PI * 2,
    });
  }

  // Enemies
  for (let i = 0; i < 6; i++) {
    enemies.push({
      x: (Math.random() - 0.5) * 14,
      y: 0,
      z: (Math.random() - 0.5) * 14,
      vx: (Math.random() - 0.5) * 0.04,
      vz: (Math.random() - 0.5) * 0.04,
      hp: 3,
      maxHp: 3,
      dead: false,
      animTimer: 0,
      alertTimer: 0,
    });
  }
}

// ===== 3D PROJECTION =====
function project(x, y, z) {
  const cx = canvas.width / 2;
  const cy = canvas.height / 2;
  const fov = 500;

  // Camera transform
  const cosA = Math.cos(cameraAngle);
  const sinA = Math.sin(cameraAngle);
  const rx = x * cosA - z * sinA;
  const rz = x * sinA + z * cosA;
  const ry = y - cameraY * 8;

  const pz = rz + 12;
  if (pz <= 0.1) return null;

  const px = cx + (rx * fov) / pz;
